INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (4, 1, 'centre_updated', 'centre', 14, '{"name":"Chisholm Village Shopping Centre","address":"42 Halley St,","suburb":"Chisholm","state":"ACT","postcode":"2905","description":"Chisholm Village Shopping Centre is located in the established suburb of Chisolm, 5 minutes from Tuggeranong in the Australian Capital Territory.\n\nThe shopping centre is anchored by a Coles and has 20 Specialty Shops including Australia Post and Anytime Fitness.\n\nPlease note that it is an external location and the centre does not provide tables or chairs. You will need to provide your own equipment.","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"chisholm-village-shopping-centre"}', NULL, '2026-03-07T14:42:55.958Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (5, 1, 'centre_updated', 'centre', 14, '{"name":"Chisholm Village Shopping Centre","address":"42 Halley St","suburb":"Chisholm","state":"ACT","postcode":"2905","description":"Chisholm Village Shopping Centre is located in the established suburb of Chisolm, 5 minutes from Tuggeranong in the Australian Capital Territory.\n\nThe shopping centre is anchored by a Coles and has 20 Specialty Shops including Australia Post and Anytime Fitness.\n\nPlease note that it is an external location and the centre does not provide tables or chairs. You will need to provide your own equipment.","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"chisholm-village-shopping-centre"}', NULL, '2026-03-07T14:43:40.437Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (6, 1, 'centre_updated', 'centre', 11, '{"name":"Bass Hill Plaza","address":"753 Hume Highway","suburb":"Bass Hill","state":"NSW","postcode":"2197","description":"<p><strong>Bass Hill Plaza</strong> is located 10km&nbsp;South of Parramatta, NSW.</p><p>&nbsp;</p><p>The centre is anchored by strong performing Woolworths, Aldi, Kmart and over 50 specialty stores with&nbsp;parking for 800 cars.&nbsp;</p><p>&nbsp;</p><p>Bass Hill Plaza serves a diverse range of cultures with 41% Australian/New Zealand, 23% European, 22% Middle East and 11% Asian.</p><p><strong>Please note that the centre does not provide tables or chairs.&nbsp; Racks are not permitted.</strong></p><p><strong>NOTE: There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar or the same items as yours during the period of your booking, particularly in festival periods.</strong></p><p>&nbsp;</p><p><strong>Centre Restrictions</strong></p><p>- Only under 18 female fashion permitted.</p><p>- No female beauty products.</p><p>- No Shoes.</p><p>- No Jewellery.</p><p>- No Fresh Flowers</p><p>- No Candles</p><p>- No Food Items</p><p>- No Headscarves / Hijabs</p><p>Max 1.5m height.</p><p>&nbsp;</p><p>Website: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://www.basshillplaza.com.au\">www.basshillplaza.com.au</a></p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"bass-hill-plaza"}', NULL, '2026-03-07T14:44:17.213Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (7, 1, 'centre_updated', 'centre', 7, '{"name":"Campbelltown Mall","address":"271 Queen Street","suburb":"Campbelltown","state":"NSW","postcode":"2560","description":"<p><strong>Campbelltown Mall</strong> is located 60km South West of Sydney and is anchored by Coles, Woolworths, ALDI, Target and a strong performing Kmart plus 102 specialty stores.</p><p>The Centre is ideally situated in the heart of Campbelltown and is close to public transport</p><p><strong>Campbelltown Mall&nbsp;</strong>also has a popular Fresh Food area with a 540 seat Food Court and over 1,800 free parking spaces.</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p>Equipment is available including trestle tables and chairs.&nbsp;</p><p>&nbsp;</p><p>&nbsp;<strong>Desired Usages</strong></p><p>- Candles</p><p>- Perfume</p><p>-&nbsp;Pets</p><p>-&nbsp;Jewellery handmade&nbsp;</p><p>- Photography</p><p>-&nbsp;Home Improvements</p><p>- Cars welcomed to Site 2</p><p>- Personalised and Seasonal Gifts</p><p>- Health &amp; Fitness&nbsp;</p><p>- Ugg Boots</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"campbelltown-mall"}', NULL, '2026-03-07T14:44:44.486Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (8, 1, 'centre_updated', 'centre', 12, '{"name":"Carnes Hill Marketplace","address":"Cnr Cowpasture and Kurrajong Roads","suburb":"Carnes Hill","state":"NSW","postcode":"2171","description":"<p><strong>Carnes Hill Marketplace</strong> is located 50km South West of Sydney in the ever-expanding Liverpool area.&nbsp;</p><p>Anchored by Woolworths and Big W,&nbsp;<strong>Carnes Hill Marketplace</strong> has more than 51 specialty stores including Dan Murphy''s and has parking for 926 cars.&nbsp;</p><p>Tables and chairs may be available from the centre upon request.&nbsp;&nbsp;</p><p>&nbsp;</p><p><em>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</em></p><p></p><p><strong>Hand Written Signage is NOT Permitted.&nbsp;</strong></p><p><strong>NO Fine Jewellery or Silver Jewellery. Fashion jewellery is permitted but cannot be more than 20% of product on display.</strong></p><p><strong>Shoes/Footwear ok in Sites 1,2 and 3 only.&nbsp;</strong></p><p><strong>No phone accessories.&nbsp; &nbsp;</strong></p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"carnes-hill-marketplace"}', NULL, '2026-03-07T14:44:52.950Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (9, 1, 'centre_updated', 'centre', 18, '{"name":"Secret Harbour Square","address":"420 Secret Harbour Boulevard","suburb":"Secret Harbour","state":"WA","postcode":"6173","description":"<p><strong>Secret Harbour Square</strong> is located 50 minutes South of Perth CBD.</p><p>The centre is anchored <strong>Woolworths</strong>, <strong>Coles</strong> and <strong>Aldi&nbsp;</strong>with 40 specialty stores.</p><p><br>Secret Harbour Square is dedicated to delivering easy, enjoyable, experiences everyday for our Secret Harbour community.</p><p>&nbsp;</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p><em>Please note that daily rates are not available at Secret Harbour Square</em></p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"secret-harbour-square"}', NULL, '2026-03-07T14:45:15.606Z');
