INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (11, 1, 'centre_updated', 'centre', 16, '{"name":"Deagon Marketplace","address":"75 Braun St","suburb":"Deagon","state":"QLD","postcode":"4017","description":"<p><strong>Deagon Marketplace</strong> is located in Deagon, 30 minutes drive North-East of Brisbane CBD. </p><p>Deagon Marketplace is a modern enclosed neighborhood shopping centre anchored by Fresh &amp; Save Food Warehouse with 17 specialty stores including The Reject Shop, Good Price Pharmacy Warehouse, Rackley Swim School, Healthworks Fitness Centre and Guppy''s Early Learning Centre. </p><p></p><p>*Please note that the centre does not provide tables or chairs.</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"deagon-marketplace"}', NULL, '2026-03-07T14:46:35.643Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (12, 1, 'centre_updated', 'centre', 13, '{"name":"Kogarah Town Centre","address":"1-9 Railway Parade,","suburb":"Kogarah","state":"NSW","postcode":"2217","description":"<p><strong>Kogarah Town Centre</strong> is located in Kogarah, 14km South of Sydney and links directly into Kogarah Railway Station. The centre and is anchored by Woolworths and Aldi with 18 Specialty Shops including Australia Post.</p><p>Top quality presentation is expected. Racks are not permitted. Fashion by approval only.</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"kogarah-town-centre"}', NULL, '2026-03-07T14:47:43.857Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (13, 1, 'centre_updated', 'centre', 10, '{"name":"Rockdale Plaza","address":"1 Rockdale Plaza Drive,","suburb":"Rockdale","state":"NSW","postcode":"2216","description":"<p><strong>Rockdale Plaza</strong> is located 12km from Sydney CBD and is anchored by Woolworths, Aldi and Big W with a strong fresh food area and over 60 Specialty Stores including&nbsp;Specsavers, Pacific Smiles Dental, Bing Lee, Tong Li Asian Grocer, Chemist Warehouse and Reject Shop.</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p><strong>Hand Written Signage is NOT Permitted.&nbsp;</strong></p><p></p><p><strong>Centre Restrictions</strong></p><p>No Clothing Racks, No As-Seen-On-TV Gadgets, Jewellery, No Hair products (incl braiding)</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"rockdale-plaza"}', NULL, '2026-03-07T14:47:53.856Z');
