INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (83, 1, 'centre_updated', 'centre', 7, '{"name":"Campbelltown Mall","address":"271 Queen Street","suburb":"Campbelltown","state":"NSW","postcode":"2560","description":"<p><strong>Campbelltown Mall</strong> is located 60km South West of Sydney and is anchored by Coles, Woolworths, ALDI, Target and a strong performing Kmart plus 102 specialty stores.</p><p>The Centre is ideally situated in the heart of Campbelltown and is close to public transport</p><p><strong>Campbelltown Mall&nbsp;</strong>also has a popular Fresh Food area with a 540 seat Food Court and over 1,800 free parking spaces.</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p>Equipment is available including trestle tables and chairs.&nbsp;</p><p>&nbsp;</p><p>&nbsp;<strong>Desired Usages</strong></p><p>- Candles</p><p>- Perfume</p><p>-&nbsp;Pets</p><p>-&nbsp;Jewellery handmade&nbsp;</p><p>- Photography</p><p>-&nbsp;Home Improvements</p><p>- Cars welcomed to Site 2</p><p>- Personalised and Seasonal Gifts</p><p>- Health &amp; Fitness&nbsp;</p><p>- Ugg Boots</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"campbelltown-mall"}', NULL, '2026-03-12T14:34:31.988Z');
