INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (109, 1, 'centre_updated', 'centre', 11, '{"name":"Bass Hill Plaza","address":"753 Hume Highway","suburb":"Bass Hill","state":"NSW","postcode":"2197","description":"<p><strong>Bass Hill Plaza</strong> is located 10km&nbsp;South of Parramatta, NSW.</p><p>&nbsp;</p><p>The centre is anchored by strong performing Woolworths, Aldi, Kmart and over 50 specialty stores with&nbsp;parking for 800 cars.&nbsp;</p><p>&nbsp;</p><p>Bass Hill Plaza serves a diverse range of cultures with 41% Australian/New Zealand, 23% European, 22% Middle East and 11% Asian.</p><p><strong>Please note that the centre does not provide tables or chairs.&nbsp; Racks are not permitted.</strong></p><p><strong>NOTE: There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar or the same items as yours during the period of your booking, particularly in festival periods.</strong></p><p>&nbsp;</p><p><strong>Centre Restrictions</strong></p><p>- Only under 18 female fashion permitted.</p><p>- No female beauty products.</p><p>- No Shoes.</p><p>- No Jewellery.</p><p>- No Fresh Flowers</p><p>- No Candles</p><p>- No Food Items</p><p>- No Headscarves / Hijabs</p><p>Max 1.5m height.</p><p>&nbsp;</p><p>Website: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://www.basshillplaza.com.au\">www.basshillplaza.com.au</a></p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","contactName":"Stuart Hely","contactEmail":"Stuart@mallincome.con","contactPhone":"0438 126 589","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"bass-hill-plaza"}', NULL, '2026-03-22T17:33:44.961Z');
INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (110, 1, 'centre_updated', 'centre', 19, '{"name":"Ocean Square","address":"Cnr Anzac Parade & Maroubra Road,","suburb":"Maroubra","state":"NSW","postcode":"2035","description":"<p><strong>Ocean Square</strong> is located in <strong>Maroubra</strong> in Sydney’s Eastern Suburbs, 10km South of Sydney CBD and is a popular shopping centre with locals as well as tourists.</p><p>&nbsp;</p><p><strong>Ocean Square</strong>&nbsp;is anchored by a strong performing <strong>Coles</strong> and <strong>Aldi</strong> and has more than 61 high-quality food retailers, cosmopolitan restaurants, essential services and boutique stores.&nbsp;&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p><p><strong>Major Stores:</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Strong-performing <strong>Coles, Aldi</strong></p><p><strong>Specialties:</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; More than 61.&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p><p><strong>Total Retail Area:&nbsp;&nbsp;&nbsp;&nbsp;</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 14,000 m2 app.</p><p><strong>Parking Spaces:&nbsp;</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;600</p><p>Trestle Tables can be provided upon request.&nbsp;</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p>Discounted rate parking can be arranged. Please advise in advance if needed.</p><p>Jewellery only permitted in Site 2.</p><p>Flowers is not permitted&nbsp;</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","contactName":"Stuart Hely","contactEmail":"Stuart@mallincome.con","contactPhone":"0438 126 589","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"ocean-square"}', NULL, '2026-03-22T17:34:14.627Z');
