INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (127, 1, 'centre_updated', 'centre', 20, '{"ownerId":3,"name":"Chullora Marketplace","address":"355-359 Waterloo Road","suburb":"Chullora","state":"NSW","postcode":"2190","description":"<p><strong>Chullora Marketplace</strong>&nbsp;is anchored by&nbsp;<strong>Woolworths</strong>,&nbsp;<strong>Aldi&nbsp;</strong>and&nbsp;<strong>Coles&nbsp;</strong>with more than 50&nbsp;specialty retailers and&nbsp;is&nbsp;located 15 kilometres West of Sydney CBD.</p><p>&nbsp;</p><p><strong>Majors</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<strong>Woolworths, Aldi, Coles</strong></p><p><strong>Specialties &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>&nbsp;Approx 50 including&nbsp;<strong>Australia Post</strong></p><p><strong>Parking</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Over 800 Parking Spaces on one level</p><p><strong>Customer Traffic&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>3&nbsp;million pa approximately</p><p>Public Liability Insurance for a minimum of $20 million is required.&nbsp;</p><p>&nbsp;</p><p><strong>Tables and tablecloths can be provided upon request.</strong></p><p>&nbsp;</p><p><strong>Restrictions:</strong></p><p>No cars or Toys</p><p>&nbsp;</p><p>Displays are to&nbsp;be tidy and present well.&nbsp;&nbsp;Items are not to be hung on the front of tables&nbsp;and&nbsp;rubbish/boxes are not to be&nbsp;visible under tables. Banners and displays are to be no higher than 1.5m.</p><p>&nbsp;</p><p>Casual lessees are expected to trade the centres full trading hours.</p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","contactName":"Stuart Hely","contactEmail":"Stuart@mallincome.con","contactPhone":"0438 126 589","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"chullora-marketplace"}', NULL, '2026-03-31T23:56:39.868Z');
