INSERT INTO "audit_log" ("id", "userId", "action", "entityType", "entityId", "changes", "ipAddress", "createdAt") VALUES (142, 1, 'centre_updated', 'centre', 21, '{"ownerId":3,"name":"Corio Village","address":"83a Purnell Rd","suburb":"Corio","state":"VIC","postcode":"3214","description":"<p><strong>Corio Village</strong>&nbsp;is located 15 minutes from Geelong CBD and less than an hour from Melbourne CBD.&nbsp;</p><p>The suburb of&nbsp;<strong>Corio</strong>&nbsp;is growing with a young and increasingly diverse primary catchment area.</p><p>Box tables and trestle tables&nbsp;and chairs may be&nbsp;available upon request.</p><p>There may potentially be&nbsp;more than one&nbsp;casual lessee selling&nbsp;similar items at the same time.&nbsp;&nbsp;</p><p>&nbsp;</p><p><strong>Majors&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp;Woolworths, Coles&nbsp;and Kmart</strong></p><p><strong>GLA&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;  &nbsp;</strong>33,354m2</p><p><strong>MAT&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>$170,000,000</p><p><strong>MAT $m</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; &nbsp; &nbsp;$7,4600</p><p><strong>Annual Traffic</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 5,011,000</p><p><strong>Specialties&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</strong>78&nbsp;</p><p><strong>Parking&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>1,400&nbsp;Spaces</p><p><br>Centre Trading Hours:</p><p>Monday, Tuesday, Wednesday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 9:00am - 5:30pm</p><p>Thursday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 9:00am - 7:00pm</p><p>Friday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;9:00am - 9:00pm</p><p>Saturday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;9:00am - 5:00pm</p><p>Sunday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;10:00am - 5:00pm</p><p>Major stores may trade longer hours. Centre hours may vary.</p><p>Website: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://coriovillage.com.au\">coriovillage.com.au</a></p>","includeInMainSite":true,"paymentMode":"stripe_with_exceptions","contactName":"Stuart Hely","contactEmail":"Stuart@mallincome.con","contactPhone":"0438 126 589","bankBsb":"","bankAccountNumber":"","bankAccountName":"","pdfUrl1":"","pdfName1":"","pdfUrl2":"","pdfName2":"","pdfUrl3":"","pdfName3":"","slug":"corio-village"}', NULL, '2026-04-02T18:13:59.314Z');
