INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (12, 'Can I give feedback and suggestions?', 'Of course, you can. We welcome your feedback which you can give by filling in the form at the bottom of the front page. We look forward to hearing from you.', 11, TRUE, '2026-03-02T00:00:10.252Z', '2026-03-07T14:06:00.828Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (6, 'Is storage available?', 'Centre''s don’t usually have storage space available.', 6, TRUE, '2026-02-16T17:05:24.732Z', '2026-02-16T17:05:24.732Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (10, 'What do I need to take to site on the day or trade?', 'It would be beneficial to take a copy of your completed License Agreement with you.', 10, TRUE, '2026-02-16T17:07:15.824Z', '2026-02-16T17:07:15.824Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (11, 'Where should I go when I arrive at the centre?', 'If you have booked casual leasing and equipment has been requested and approved, you can go straight to the site. If you have a vacant shop license, you should pop into Centre Management. If there are security officers in the centre at the time and you have any questions, they should be able to assist you if needed.', 13, TRUE, '2026-02-16T17:07:51.361Z', '2026-03-08T12:56:44.825Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (2, 'Do I need insurance?', 'A Licensee must arrange and maintain a public liability policy for the minimum amount of $20 million and any other insurances reasonably requested from time to time. The policy is to remain in place at least 30 days after end of the license date. ', 15, TRUE, '2026-02-16T17:03:48.652Z', '2026-03-08T12:57:44.600Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (14, 'About US', '.', 2, TRUE, '2026-03-08T12:58:07.335Z', '2026-03-08T12:58:07.335Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (3, 'For how long can I book?', 'That depends on the centre and whether you are booking casual leasing or a vacant shop. Generally, a casual leasing booking can be from one day and up to 6 months for vacant shops depending on the relevant law in your State or Territory.', 3, TRUE, '2026-02-16T17:04:12.249Z', '2026-03-06T17:18:42.041Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (4, 'Can I make a long-term booking?', 'The maximum length of time for a booking is 6 months. If you wish to continue trading, depending on the State or Territory laws, you may be required to relocate within the centre or fully vacate the premises for a minimum of 24 hours. ', 4, TRUE, '2026-02-16T17:04:45.842Z', '2026-03-06T17:19:34.968Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (5, 'Does the price I pay include electricity?', 'Unless stated otherwise, electricity is included in casual leasing licensing fees however it is usually an additional cost in vacant shops. Check details on the relevant listing or ask us.', 5, TRUE, '2026-02-16T17:05:01.869Z', '2026-03-06T17:19:58.480Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (8, 'I have completed my booking. What do I do to start trading?', 'If you have received confirmation of your booking and made payment, then follow the bump-in pack instructions that may have been provided with your confirmation email. If one was not provided, the equipment that you have requested from that centre will be set up prior to your arrival.', 8, TRUE, '2026-02-16T17:05:59.853Z', '2026-03-06T17:21:18.861Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (13, 'About MALLincome.com', 'This is the ultimate and most advanced Casual Leasing Platform ever created.  It has come from decades of casual leasing and shopping centre management experience providing unmatched control for landlords and managing agents - as well as a seamless booking experience for users.', 1, TRUE, '2026-03-08T12:50:07.723Z', '2026-03-08T12:55:52.318Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (1, 'How do I find the site that I want?', 'Simply type in what you are looking for - For example, Need 4 tables to sell shoes in Kogarah in June OR Where can I sell shoes in Sydney''s West? OR I need 3x4m to set up a picture display in Campbelltown in June. You get the idea. Now, feel free to give it a go!', 7, TRUE, '2026-02-16T14:32:11.429Z', '2026-03-08T12:56:21.702Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (7, 'Is seating available?', 'Seating options (if any) will be supplied as an option when selecting your equipment requirements.', 9, TRUE, '2026-02-16T17:05:42.391Z', '2026-03-08T12:56:28.932Z');
INSERT INTO "faqs" ("id", "question", "answer", "display_order", "is_active", "created_at", "updated_at") VALUES (9, 'How can I make payment?', 'Payment for most bookings is made via credit card at the time of booking. 
