INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (7, 1, 'Campbelltown Mall', NULL, '271 Queen Street', 'Campbelltown', NULL, 'NSW', '2560', '<p><strong>Campbelltown Mall</strong> is located 60km South West of Sydney and is anchored by Coles, Woolworths, ALDI, Target and a strong performing Kmart plus 102 specialty stores.</p><p>The Centre is ideally situated in the heart of Campbelltown and is close to public transport</p><p><strong>Campbelltown Mall&nbsp;</strong>also has a popular Fresh Food area with a 540 seat Food Court and over 1,800 free parking spaces.</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p>Equipment is available including trestle tables and chairs.&nbsp;</p><p>&nbsp;</p><p>&nbsp;<strong>Desired Usages</strong></p><p>- Candles</p><p>- Perfume</p><p>-&nbsp;Pets</p><p>-&nbsp;Jewellery handmade&nbsp;</p><p>- Photography</p><p>-&nbsp;Home Improvements</p><p>- Cars welcomed to Site 2</p><p>- Personalised and Seasonal Gifts</p><p>- Health &amp; Fitness&nbsp;</p><p>- Ugg Boots</p>', '-34.0692830', '150.8111367', 'Coles, KMart, Aldi, Target, Woolworths', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 75, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-16T23:34:31.411Z', '2026-02-16T23:34:31.411Z', 'campbelltown-mall', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (9, 1, 'Wanneroo Central', NULL, '950 Wanneroo Road,', 'Wanneroo', NULL, 'WA', '6065', '<p><strong>Wanneroo Central</strong> is a sub-regional shopping centre, 30 minutes North of Perth and is&nbsp;anchored by Coles, Kmart, Aldi with around 50 specialty stores.</p><p>&nbsp;</p><p><strong>NO EQUIPMENT AVAILABLE FROM THE CENTRE.</strong></p><p><strong>CARS cannot be accomodated at this centre.</strong></p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p>', '-31.7529648', '115.8041616', 'Coles, Woolworths, Target', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-16T23:34:31.424Z', '2026-02-16T23:34:31.424Z', 'wanneroo-central', NULL, 'stripe_with_exceptions', '', '', '', NULL);
