INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (15, 1, 'Kallangur Fair Shopping Centre', NULL, '1477 Anzac Avenue,', 'Kallangur', NULL, 'QLD', '4503', '<p><strong>Kallangur Fair</strong> is located in the Moreton Bay Region, 35 minutes North of Brisbane and is the dominant centre in the catchment area. </p><p>The centre is anchored by Woolworths and has 11 specialty stores.</p><p>Parking is free with 270 spaces.</p>', '-27.2513807', '152.9992194', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-22T18:25:59.142Z', '2026-02-22T18:25:59.142Z', 'kallangur-fair-shopping-centre', NULL, 'stripe_with_exceptions', NULL, NULL, NULL, NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (16, 1, 'Deagon Marketplace', NULL, '75 Braun St', 'Deagon', NULL, 'QLD', '4017', '<p><strong>Deagon Marketplace</strong> is located in Deagon, 30 minutes drive North-East of Brisbane CBD. </p><p>Deagon Marketplace is a modern enclosed neighborhood shopping centre anchored by Fresh &amp; Save Food Warehouse with 17 specialty stores including The Reject Shop, Good Price Pharmacy Warehouse, Rackley Swim School, Healthworks Fitness Centre and Guppy''s Early Learning Centre. </p><p></p><p>*Please note that the centre does not provide tables or chairs.</p>', '-27.3290379', '153.0566522', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-22T18:54:34.268Z', '2026-02-22T18:54:34.268Z', 'deagon-marketplace', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (6, 1, 'Highlands Marketplace', NULL, '197 Old Hume Hwy,', 'Mittagong', NULL, 'NSW', '2575', '<p><strong>Highlands Marketplace Mittagong&nbsp;</strong>is<strong>&nbsp;</strong>only 45 minutes from Western Sydney and&nbsp;is anchored by <strong>Woolworths</strong> and <strong>Big W</strong>&nbsp;with 35 specialty stores.</p><p>&nbsp;</p><p><strong>Mittagong</strong> has a growing population of families and retirees enjoying the better lifestyle.</p><p>&nbsp;</p><p>With a great mix of stores, plenty of parking and family-friendly facilities, Highlands Marketplace has all your shopping needs covered in one convenient location.&nbsp;</p><p>There may potentially be&nbsp;more than one&nbsp;casual lessee selling&nbsp;similar items at the same time.&nbsp;</p>', '-34.4469011', '150.4381943', 'Woolworths, BigW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-16T23:34:31.401Z', '2026-02-16T23:34:31.401Z', 'highlands-marketplace', NULL, 'stripe_with_exceptions', NULL, NULL, NULL, NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (13, 1, 'Kogarah Town Centre', NULL, '1-9 Railway Parade,', 'Kogarah', NULL, 'NSW', '2217', '<p><strong>Kogarah Town Centre</strong> is located in Kogarah, 14km South of Sydney and links directly into Kogarah Railway Station. The centre and is anchored by Woolworths and Aldi with 18 Specialty Shops including Australia Post.</p><p>Top quality presentation is expected. Racks are not permitted. Fashion by approval only.</p>', '-33.9622840', '151.1327190', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-21T20:25:06.483Z', '2026-02-21T20:25:06.483Z', 'kogarah-town-centre', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (10, 1, 'Rockdale Plaza', NULL, '1 Rockdale Plaza Drive,', 'Rockdale', NULL, 'NSW', '2216', '<p><strong>Rockdale Plaza</strong> is located 12km from Sydney CBD and is anchored by Woolworths, Aldi and Big W with a strong fresh food area and over 60 Specialty Stores including&nbsp;Specsavers, Pacific Smiles Dental, Bing Lee, Tong Li Asian Grocer, Chemist Warehouse and Reject Shop.</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p><strong>Hand Written Signage is NOT Permitted.&nbsp;</strong></p><p></p><p><strong>Centre Restrictions</strong></p><p>No Clothing Racks, No As-Seen-On-TV Gadgets, Jewellery, No Hair products (incl braiding)</p>', '-33.9579010', '151.1411438', 'Coles, Woolworths', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-16T23:34:31.429Z', '2026-02-16T23:34:31.429Z', 'rockdale-plaza', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (17, 3, 'Eastgate Bondi Junction', NULL, '71-91 Spring Street,', 'Bondi Junction', NULL, 'NSW', '2022', '<p><strong>Eastgate Bondi Junction</strong> is a well-established sub-regional Shopping Centre located in the heart of Bondi Junction, Sydney between Spring Street and Ebley Street and adjacent to the bustling Oxford Street.</p><p>&nbsp;</p><p>The centre is conveniently positioned only 200m from Bondi Junctions Bus and Train Interchange and Westfield Bondi.&nbsp;</p><p>No food casual leasing.</p><p>&nbsp;</p><p>Parking for casual lessees is on the rooftop for $19.00 per day.</p><p>&nbsp;</p><p><strong>Eastgate Bondi Junction</strong>&nbsp;is anchored by <strong>Coles, Aldi </strong>and<strong> Kmart</strong> with over 25 specialty stores.&nbsp;</p>', '-33.8929668', '151.2480285', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-01T20:51:29.404Z', '2026-03-01T20:51:29.404Z', 'eastgate-bondi-junction', NULL, 'stripe_with_exceptions', NULL, NULL, NULL, NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (18, 2, 'Secret Harbour Square', NULL, '420 Secret Harbour Boulevard', 'Secret Harbour', NULL, 'WA', '6173', '<p><strong>Secret Harbour Square</strong> is located 50 minutes South of Perth CBD.</p><p>The centre is anchored <strong>Woolworths</strong>, <strong>Coles</strong> and <strong>Aldi&nbsp;</strong>with 40 specialty stores.</p><p><br>Secret Harbour Square is dedicated to delivering easy, enjoyable, experiences everyday for our Secret Harbour community.</p><p>&nbsp;</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p><em>Please note that daily rates are not available at Secret Harbour Square</em></p>', '-32.4086494', '115.7590415', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-03-05T13:13:05.530Z', '2026-03-05T13:13:05.530Z', 'secret-harbour-square', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (8, 1, 'Pacific Square', NULL, 'Cnr Anzac Parade & Maroubra Road,', 'Maroubra', NULL, 'NSW', '2035', '<p><strong>Pacific Square</strong> is located in <strong>Maroubra</strong> in Sydney’s Eastern Suburbs, 10km South of Sydney CBD and is a popular shopping centre with locals as well as tourists.</p><p>&nbsp;</p><p><strong>Pacific Square</strong>&nbsp;is anchored by a strong performing <strong>Coles</strong> and <strong>Aldi</strong> and has more than 60 high-quality food retailers, cosmopolitan restaurants, essential services and boutique stores.&nbsp;&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p><p><strong>Major Stores:</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Strong-performing <strong>Coles, Aldi</strong></p><p><strong>Specialties:</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; More than 60.&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p><p><strong>Total Retail Area:&nbsp;&nbsp;&nbsp;&nbsp;</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 13,807 m2 app.</p><p><strong>Parking Spaces:&nbsp;</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;620</p><p>Trestle Tables can be provided upon request.&nbsp;</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p>Discounted rate parking can be arranged. Please advise in advance if needed.</p><p>Jewellery only permitted in Site 2.</p><p>Flowers is not permitted&nbsp;</p><p><strong>Desired&nbsp;Usages</strong></p><p><strong>&nbsp; &nbsp;- </strong>Activewear</p><p><strong>&nbsp; &nbsp;- </strong>Boutique Clothing</p><p><strong>&nbsp; &nbsp;- </strong>Pet Supplies</p><p><strong>&nbsp; &nbsp;- </strong>Antiques and Giftware</p><p>&nbsp; &nbsp;- Specialty Foods such as Chocolates, Organic, Etc.</p><p>&nbsp; &nbsp;- Financial Services</p><p>&nbsp; &nbsp;- Cookware</p><p>&nbsp; &nbsp;- Health &amp; Theraupetic Goods</p><p><strong>Hand Written Signage is NOT Permitted.</strong></p><p><strong>Clothing Racks and Helium Balloons are not permitted.</strong></p>', '-33.9409229', '151.2386112', 'Coles, Woolworths', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-16T23:34:31.419Z', '2026-02-16T23:34:31.419Z', 'pacific-square', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (19, 2, 'Ocean Square', NULL, '111 Maroubra Road,', 'Maroubra', NULL, 'NSW', '2035', '<p><strong>Ocean Square</strong> is located in <strong>Maroubra</strong> in Sydney’s Eastern Suburbs, 10km South of Sydney CBD and is a popular shopping centre with locals as well as tourists.</p><p>&nbsp;</p><p><strong>Ocean Square</strong>&nbsp;is anchored by a strong performing <strong>Coles</strong> and <strong>Aldi</strong> and has more than 61 high-quality food retailers, cosmopolitan restaurants, essential services and boutique stores.&nbsp;&nbsp;</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p><p><strong>Major Stores:</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Strong-performing <strong>Coles, Aldi</strong></p><p><strong>Specialties:</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; More than 61.&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</p><p><strong>Total Retail Area:&nbsp;&nbsp;&nbsp;&nbsp;</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 14,000 m2 app.</p><p><strong>Parking Spaces:&nbsp;</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;600</p><p>Trestle Tables can be provided upon request.&nbsp;</p><p>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</p><p>Discounted rate parking can be arranged. Please advise in advance if needed.</p><p>Jewellery only permitted in Site 2.</p><p>Flowers is not permitted&nbsp;</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 18, 7, '0438 671 685', 'Stuart@mallincome.con', NULL, NULL, '', '', '', '', '', '', '2026-03-14T15:01:06.903Z', '2026-03-14T15:01:06.903Z', 'ocean-square', NULL, 'stripe_with_exceptions', '', '', '', 'Stuart Hely');
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (12, 1, 'Carnes Hill Marketplace', NULL, 'Cnr Cowpasture and Kurrajong Roads', 'Carnes Hill', NULL, 'NSW', '2171', '<p><strong>Carnes Hill Marketplace</strong> is located 50km South West of Sydney in the ever-expanding Liverpool area.&nbsp;</p><p>Anchored by Woolworths and Big W,&nbsp;<strong>Carnes Hill Marketplace</strong> has more than 51 specialty stores including Dan Murphy''s and has parking for 926 cars.&nbsp;</p><p>Tables and chairs may be available from the centre upon request.&nbsp;&nbsp;</p><p>&nbsp;</p><p><em>There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar items&nbsp;to yours during the period of your booking.</em></p><p></p><p><strong>Hand Written Signage is NOT Permitted.&nbsp;</strong></p><p><strong>NO Fine Jewellery or Silver Jewellery. Fashion jewellery is permitted but cannot be more than 20% of product on display.</strong></p><p><strong>Shoes/Footwear ok in Sites 1,2 and 3 only.&nbsp;</strong></p><p><strong>No phone accessories.&nbsp; &nbsp;</strong></p>', '-33.9372046', '150.8456148', 'Coles, Woolworths', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 35, 0, NULL, NULL, NULL, NULL, '', '', '', '', '', '', '2026-02-16T23:34:31.441Z', '2026-02-16T23:34:31.441Z', 'carnes-hill-marketplace', NULL, 'stripe_with_exceptions', '', '', '', NULL);
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (11, 1, 'Bass Hill Plaza', NULL, '753 Hume Highway', 'Bass Hill', NULL, 'NSW', '2197', '<p><strong>Bass Hill Plaza</strong> is located 10km&nbsp;South of Parramatta, NSW.</p><p>&nbsp;</p><p>The centre is anchored by strong performing Woolworths, Aldi, Kmart and over 50 specialty stores with&nbsp;parking for 800 cars.&nbsp;</p><p>&nbsp;</p><p>Bass Hill Plaza serves a diverse range of cultures with 41% Australian/New Zealand, 23% European, 22% Middle East and 11% Asian.</p><p><strong>Please note that the centre does not provide tables or chairs.&nbsp; Racks are not permitted.</strong></p><p><strong>NOTE: There may potentially be other&nbsp;casual lessees&nbsp;selling&nbsp;similar or the same items as yours during the period of your booking, particularly in festival periods.</strong></p><p>&nbsp;</p><p><strong>Centre Restrictions</strong></p><p>- Only under 18 female fashion permitted.</p><p>- No female beauty products.</p><p>- No Shoes.</p><p>- No Jewellery.</p><p>- No Fresh Flowers</p><p>- No Candles</p><p>- No Food Items</p><p>- No Headscarves / Hijabs</p><p>Max 1.5m height.</p><p>&nbsp;</p><p>Website: <a target="_blank" rel="noopener noreferrer nofollow" href="http://www.basshillplaza.com.au">www.basshillplaza.com.au</a></p>', '-33.8995353', '150.9936807', 'Woolworths', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, '/maps/centres/11-1771326066287.png', 12, 0, '0438 126 589', 'Stuart@mallincome.con', NULL, NULL, '', '', '', '', '', '', '2026-02-16T23:34:31.435Z', '2026-02-16T23:34:31.435Z', 'bass-hill-plaza', NULL, 'stripe_with_exceptions', '', '', '', 'Stuart Hely');
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (20, 3, 'Chullora Marketplace', NULL, '355-359 Waterloo Road', 'Chullora', NULL, 'NSW', '2190', '<p><strong>Chullora Marketplace</strong>&nbsp;is anchored by&nbsp;<strong>Woolworths</strong>,&nbsp;<strong>Aldi&nbsp;</strong>and&nbsp;<strong>Coles&nbsp;</strong>with more than 50&nbsp;specialty retailers and&nbsp;is&nbsp;located 15 kilometres West of Sydney CBD.</p><p>&nbsp;</p><p><strong>Majors</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;<strong>Woolworths, Aldi, Coles</strong></p><p><strong>Specialties &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>&nbsp;Approx 50 including&nbsp;<strong>Australia Post</strong></p><p><strong>Parking</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Over 800 Parking Spaces on one level</p><p><strong>Customer Traffic&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>3&nbsp;million pa approximately</p><p>Public Liability Insurance for a minimum of $20 million is required.&nbsp;</p><p>&nbsp;</p><p><strong>Tables and tablecloths can be provided upon request.</strong></p><p>&nbsp;</p><p><strong>Restrictions:</strong></p><p>No cars or Toys</p><p>&nbsp;</p><p>Displays are to&nbsp;be tidy and present well.&nbsp;&nbsp;Items are not to be hung on the front of tables&nbsp;and&nbsp;rubbish/boxes are not to be&nbsp;visible under tables. Banners and displays are to be no higher than 1.5m.</p><p>&nbsp;</p><p>Casual lessees are expected to trade the centres full trading hours.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, '0438 126 589', 'Stuart@mallincome.con', NULL, NULL, '', '', '', '', '', '', '2026-03-31T18:36:00.864Z', '2026-03-31T18:36:00.864Z', 'chullora-marketplace', NULL, 'stripe_with_exceptions', '', '', '', 'Stuart Hely');
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (21, 3, 'Corio Village', NULL, '83a Purnell Rd', 'Corio', NULL, 'VIC', '3214', '<p><strong>Corio Village</strong>&nbsp;is located 15 minutes from Geelong CBD and less than an hour from Melbourne CBD.&nbsp;</p><p>The suburb of&nbsp;<strong>Corio</strong>&nbsp;is growing with a young and increasingly diverse primary catchment area.</p><p>Box tables and trestle tables&nbsp;and chairs may be&nbsp;available upon request.</p><p>There may potentially be&nbsp;more than one&nbsp;casual lessee selling&nbsp;similar items at the same time.&nbsp;&nbsp;</p><p>&nbsp;</p><p><strong>Majors&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp;Woolworths, Coles&nbsp;and Kmart</strong></p><p><strong>GLA&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;  &nbsp;</strong>33,354m2</p><p><strong>MAT&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>$170,000,000</p><p><strong>MAT $m</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; &nbsp; &nbsp;$7,4600</p><p><strong>Annual Traffic</strong>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 5,011,000</p><p><strong>Specialties&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</strong>78&nbsp;</p><p><strong>Parking&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</strong>1,400&nbsp;Spaces</p><p><br>Centre Trading Hours:</p><p>Monday, Tuesday, Wednesday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 9:00am - 5:30pm</p><p>Thursday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 9:00am - 7:00pm</p><p>Friday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;9:00am - 9:00pm</p><p>Saturday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;9:00am - 5:00pm</p><p>Sunday&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;10:00am - 5:00pm</p><p>Major stores may trade longer hours. Centre hours may vary.</p><p>Website: <a target="_blank" rel="noopener noreferrer nofollow" href="http://coriovillage.com.au">coriovillage.com.au</a></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, '0438 126 589', 'Stuart@mallincome.con', NULL, NULL, '', '', '', '', '', '', '2026-04-02T17:45:59.855Z', '2026-04-02T17:45:59.855Z', 'corio-village', NULL, 'stripe_with_exceptions', '', '', '', 'Stuart Hely');
INSERT INTO "shopping_centres" ("id", "ownerId", "name", "centreCode", "address", "suburb", "city", "state", "postcode", "description", "latitude", "longitude", "majors", "numberOfSpecialties", "weeklyReportEmail1", "weeklyReportEmail2", "weeklyReportEmail3", "weeklyReportEmail4", "weeklyReportEmail5", "weeklyReportEmail6", "weeklyReportEmail7", "weeklyReportEmail8", "weeklyReportEmail9", "weeklyReportEmail10", "weeklyReportTimezone", "weeklyReportNextOverrideDay", "includeInMainSite", "mapImageUrl", "totalTablesAvailable", "totalChairsAvailable", "contactPhone", "contactEmail", "operatingHours", "policies", "pdfUrl1", "pdfName1", "pdfUrl2", "pdfName2", "pdfUrl3", "pdfName3", "createdAt", "updatedAt", "slug", "portfolioId", "paymentMode", "bankBsb", "bankAccountNumber", "bankAccountName", "contactName") VALUES (22, 2, 'Waverley Gardens Shopping Centre', NULL, '271 Police Road', 'Mulgrave', NULL, 'VIC', '3170', '<p>Waverley Gardens is anchored by Woolworths, Coles and Aldi supermarkets with Big W with of over 100 specialty stores.</p><p></p><p>The Centre is located approximately 23kms from the Melbourne CBD, adjacent to the Monash Freeway and is accessible via the East Link tollway.</p><p></p><p>Telephone: 03 9547 6088</p><p>Website: <a target="_blank" rel="noopener noreferrer nofollow" href="http://www.waverleygardens.com.au">www.waverleygardens.com.au</a></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Australia/Sydney', NULL, TRUE, NULL, 0, 0, '0438 126 589', 'Stuart@mallincome.con', NULL, NULL, '', '', '', '', '', '', '2026-04-05T17:38:05.711Z', '2026-04-05T17:38:05.711Z', 'waverley-gardens-shopping-centre', NULL, 'stripe_with_exceptions', '', '', '', 'Stuart Hely');
